(function () {
  'use strict'

  // ============ Configuration ============
  var config = window.openChatConfig || {}
  var baseUrl = (config.baseUrl || '').replace(/\/+$/, '')
  if (!baseUrl) {
    console.error('[open-chat-embed] baseUrl is required in window.openChatConfig')
    return
  }
  if (!config.token) {
    console.error('[open-chat-embed] token is required in window.openChatConfig')
    return
  }

  var iconUrl = config.iconUrl || ''
  var iconName = config.icon || 'robot'
  var agentId = config.agentId || ''
  var windowTitle = config.windowTitle || 'AI \u52A9\u624B'
  var theme = config.theme || 'light'
  var locale = config.locale || 'zh-Hans'

  var size = config.windowSize || {}
  var winW = size.width || 400
  var winH = size.height || 600
  var minW = size.minWidth || 320
  var minH = size.minHeight || 400
  var maxW = size.maxWidth || 800
  var maxH = size.maxHeight || 900

  var POS_STORAGE_KEY = 'open_chat_embed_button_pos'
  var SIZE_STORAGE_KEY = 'open_chat_embed_window_size'

  // Theme color mapping
  var themeColors = {
    light: { bg: '#ffffff', border: '#e5e5e5' },
    dark: { bg: '#1f2937', border: '#374151' },
    'tech-blue': { bg: 'rgba(14,25,51,0.98)', border: 'rgba(100,150,255,0.25)' },
  }
  var tc = themeColors[theme] || themeColors.light

  // Header style (user configurable)
  var hs = config.headerStyle || {}
  var headerBg = hs.backgroundColor || tc.bg
  var headerBorder = hs.borderColor || tc.border
  var headerText = hs.textColor || '#333'
  var headerIcon = hs.iconColor || '#666'
  var headerBtnHover = hs.buttonHoverBg || 'rgba(0,0,0,0.06)'

  // Restore saved size
  try {
    var savedSize = JSON.parse(localStorage.getItem(SIZE_STORAGE_KEY))
    if (savedSize && typeof savedSize.w === 'number') {
      winW = Math.min(maxW, Math.max(minW, savedSize.w))
      winH = Math.min(maxH, Math.max(minH, savedSize.h))
    }
  } catch (e) { /* ignore */ }

  var isOpen = false
  var isMobile = window.innerWidth < 768

  // ============ Floating Button ============
  var btn = document.createElement('div')
  btn.id = 'oc-embed-btn'
  btn.style.cssText = [
    'position:fixed',
    'z-index:9998',
    'width:52px',
    'height:52px',
    'border-radius:50%',
    'cursor:pointer',
    'box-shadow:0 2px 12px rgba(0,0,0,0.15)',
    'display:flex',
    'align-items:center',
    'justify-content:center',
    'transition:transform 0.2s,box-shadow 0.2s',
    'user-select:none',
    '-webkit-user-select:none',
    'background-color:' + (config.bubbleStyle?.backgroundColor || '#1C64F2'),
    'background-size:cover',
    'background-position:center',
    'touch-action:none',
  ].join(';')

  if (iconUrl) {
    btn.style.backgroundImage = 'url(' + iconUrl + ')'
  } else {
    btn.style.backgroundImage = 'url(' + baseUrl + '/images/embed-icons/' + iconName + '.svg)'
  }

  btn.addEventListener('mouseenter', function () {
    btn.style.transform = 'scale(1.08)'
    btn.style.boxShadow = '0 4px 20px rgba(0,0,0,0.25)'
  })
  btn.addEventListener('mouseleave', function () {
    if (isDragging) return
    btn.style.transform = 'scale(1)'
    btn.style.boxShadow = '0 2px 12px rgba(0,0,0,0.15)'
  })

  // Restore saved position
  var btnX = window.innerWidth - 76
  var btnY = window.innerHeight - 76
  try {
    var saved = JSON.parse(localStorage.getItem(POS_STORAGE_KEY))
    if (saved && typeof saved.x === 'number' && typeof saved.y === 'number') {
      btnX = Math.min(window.innerWidth - 52, Math.max(0, saved.x))
      btnY = Math.min(window.innerHeight - 52, Math.max(0, saved.y))
    }
  } catch (e) { /* ignore */ }
  btn.style.left = btnX + 'px'
  btn.style.top = btnY + 'px'

  // Drag support
  var isDragging = false
  var dragStartX = 0
  var dragStartY = 0
  var dragStartBtnX = 0
  var dragStartBtnY = 0
  var hasMoved = false

  function onDragStart(e) {
    if (e.target.tagName === 'IFRAME') return
    isDragging = true
    hasMoved = false
    var pos = e.touches ? e.touches[0] : e
    dragStartX = pos.clientX
    dragStartY = pos.clientY
    dragStartBtnX = parseInt(btn.style.left, 10)
    dragStartBtnY = parseInt(btn.style.top, 10)
    btn.style.transition = 'none'
  }

  function onDragMove(e) {
    if (!isDragging) return
    var pos = e.touches ? e.touches[0] : e
    var dx = pos.clientX - dragStartX
    var dy = pos.clientY - dragStartY
    if (Math.abs(dx) > 3 || Math.abs(dy) > 3) hasMoved = true
    var nx = Math.min(window.innerWidth - 52, Math.max(0, dragStartBtnX + dx))
    var ny = Math.min(window.innerHeight - 52, Math.max(0, dragStartBtnY + dy))
    btn.style.left = nx + 'px'
    btn.style.top = ny + 'px'
  }

  function onDragEnd() {
    if (!isDragging) return
    isDragging = false
    btn.style.transition = 'transform 0.2s, box-shadow 0.2s'
    btn.style.transform = 'scale(1)'
    btn.style.boxShadow = '0 2px 12px rgba(0,0,0,0.15)'
    try {
      localStorage.setItem(POS_STORAGE_KEY, JSON.stringify({
        x: parseInt(btn.style.left, 10),
        y: parseInt(btn.style.top, 10),
      }))
    } catch (e) { /* ignore */ }
  }

  function onBtnClick() {
    if (hasMoved) return
    openWindow()
  }

  btn.addEventListener('mousedown', onDragStart)
  btn.addEventListener('touchstart', onDragStart, { passive: false })
  window.addEventListener('mousemove', onDragMove)
  window.addEventListener('touchmove', onDragMove, { passive: false })
  window.addEventListener('mouseup', onDragEnd)
  window.addEventListener('touchend', onDragEnd)
  btn.addEventListener('click', onBtnClick)

  document.body.appendChild(btn)

  // ============ Window Container ============
  var container = document.createElement('div')
  container.id = 'oc-embed-window'
  container.style.cssText = [
    'position:fixed',
    'z-index:9999',
    'display:none',
    'flex-direction:column',
    'border-radius:8px',
    'overflow:hidden',
    'box-shadow:0 4px 24px rgba(0,0,0,0.18)',
    'background:' + tc.bg,
    'width:' + winW + 'px',
    'height:' + winH + 'px',
    'min-width:' + minW + 'px',
    'min-height:' + minH + 'px',
    'max-width:' + maxW + 'px',
    'max-height:' + maxH + 'px',
  ].join(';')

  // ============ Title Bar ============
  var titleBar = document.createElement('div')
  titleBar.style.cssText = [
    'display:flex',
    'align-items:center',
    'justify-content:space-between',
    'height:40px',
    'padding:0 8px',
    'cursor:move',
    'flex-shrink:0',
    'user-select:none',
    '-webkit-user-select:none',
    'touch-action:none',
    'background:' + headerBg,
    'border-bottom:1px solid ' + headerBorder,
  ].join(';')

  // ☰ toggle sidebar button
  var menuBtn = document.createElement('button')
  menuBtn.innerHTML = '<svg width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="' + headerIcon + '" stroke-width="1.5"><path d="M1 2h12M1 7h12M1 12h12"/></svg>'
  menuBtn.style.cssText = [
    'display:flex',
    'align-items:center',
    'justify-content:center',
    'width:28px',
    'height:28px',
    'border:none',
    'background:none',
    'cursor:pointer',
    'border-radius:4px',
    'flex-shrink:0',
  ].join(';')
  menuBtn.addEventListener('mouseenter', function () { menuBtn.style.background = headerBtnHover })
  menuBtn.addEventListener('mouseleave', function () { menuBtn.style.background = 'none' })

  // Title text
  var titleSpan = document.createElement('span')
  titleSpan.textContent = windowTitle
  titleSpan.style.cssText = 'font-size:13px;font-weight:500;color:' + headerText + ';overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1;margin:0 8px;cursor:move;'

  // × close button
  var closeBtn = document.createElement('button')
  closeBtn.innerHTML = '<svg width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="' + headerIcon + '" stroke-width="1.5"><path d="M3 3l8 8M11 3l-8 8"/></svg>'
  closeBtn.style.cssText = [
    'display:flex',
    'align-items:center',
    'justify-content:center',
    'width:28px',
    'height:28px',
    'border:none',
    'background:none',
    'cursor:pointer',
    'border-radius:4px',
    'flex-shrink:0',
  ].join(';')
  closeBtn.addEventListener('mouseenter', function () { closeBtn.style.background = headerBtnHover })
  closeBtn.addEventListener('mouseleave', function () { closeBtn.style.background = 'none' })
  closeBtn.addEventListener('click', function (e) { e.stopPropagation(); closeWindow() })

  titleBar.appendChild(menuBtn)
  titleBar.appendChild(titleSpan)
  titleBar.appendChild(closeBtn)

  // ============ Iframe ============
  var iframe = document.createElement('iframe')
  var embedUrl = baseUrl + '/embed'
  var params = ['token=' + encodeURIComponent(config.token)]
  if (agentId) params.push('agentId=' + encodeURIComponent(agentId))
  if (theme) params.push('theme=' + encodeURIComponent(theme))
  if (locale) params.push('locale=' + encodeURIComponent(locale))
  if (windowTitle) params.push('title=' + encodeURIComponent(windowTitle))
  iframe.src = embedUrl + '?' + params.join('&')
  iframe.style.cssText = [
    'flex:1',
    'border:none',
    'width:100%',
    'min-height:0',
  ].join(';')
  iframe.setAttribute('allow', 'microphone')
  iframe.setAttribute('title', 'Open Chat')

  container.appendChild(titleBar)
  container.appendChild(iframe)
  document.body.appendChild(container)

  // ============ Window Drag (via titleBar) ============
  var isWinDragging = false
  var winDragStartX = 0
  var winDragStartY = 0
  var winStartLeft = 0
  var winStartTop = 0

  function onWinDragStart(e) {
    if (e.target.tagName === 'BUTTON') return
    isWinDragging = true
    var pos = e.touches ? e.touches[0] : e
    winDragStartX = pos.clientX
    winDragStartY = pos.clientY
    winStartLeft = parseInt(container.style.left, 10) || (window.innerWidth - winW) / 2
    winStartTop = parseInt(container.style.top, 10) || (window.innerHeight - winH) / 2
    e.preventDefault()
  }

  function onWinDragMove(e) {
    if (!isWinDragging) return
    var pos = e.touches ? e.touches[0] : e
    var nx = winStartLeft + (pos.clientX - winDragStartX)
    var ny = winStartTop + (pos.clientY - winDragStartY)
    container.style.left = nx + 'px'
    container.style.top = ny + 'px'
    container.style.right = 'auto'
    container.style.bottom = 'auto'
  }

  function onWinDragEnd() {
    isWinDragging = false
  }

  titleBar.addEventListener('mousedown', onWinDragStart)
  titleBar.addEventListener('touchstart', onWinDragStart, { passive: false })
  window.addEventListener('mousemove', onWinDragMove)
  window.addEventListener('touchmove', onWinDragMove, { passive: false })
  window.addEventListener('mouseup', onWinDragEnd)
  window.addEventListener('touchend', onWinDragEnd)

  // ============ Sidebar toggle (postMessage into iframe) ============
  menuBtn.addEventListener('click', function (e) {
    e.stopPropagation()
    iframe.contentWindow.postMessage({ type: 'com.openchat.embed', action: 'toggle-sidebar' }, '*')
  })

  // ============ Resize Handle ============
  var resizeHandle = document.createElement('div')
  resizeHandle.style.cssText = [
    'position:absolute',
    'bottom:0',
    'right:0',
    'width:16px',
    'height:16px',
    'cursor:nwse-resize',
    'z-index:10',
  ].join(';')
  resizeHandle.innerHTML = '<svg width="12" height="12" viewBox="0 0 12 12" fill="none" stroke="#999" stroke-width="1.5" style="position:absolute;bottom:2px;right:2px;pointer-events:none"><path d="M10 2v8H2"/><path d="M10 6v4H6"/></svg>'

  var isResizing = false
  var resizeStartX = 0
  var resizeStartY = 0
  var resizeStartW = 0
  var resizeStartH = 0

  function onResizeStart(e) {
    isResizing = true
    var pos = e.touches ? e.touches[0] : e
    resizeStartX = pos.clientX
    resizeStartY = pos.clientY
    resizeStartW = container.offsetWidth
    resizeStartH = container.offsetHeight
    e.preventDefault()
    e.stopPropagation()
  }

  function onResizeMove(e) {
    if (!isResizing) return
    var pos = e.touches ? e.touches[0] : e
    var nw = Math.min(maxW, Math.max(minW, resizeStartW + (pos.clientX - resizeStartX)))
    var nh = Math.min(maxH, Math.max(minH, resizeStartH + (pos.clientY - resizeStartY)))
    container.style.width = nw + 'px'
    container.style.height = nh + 'px'
    try {
      localStorage.setItem(SIZE_STORAGE_KEY, JSON.stringify({ w: nw, h: nh }))
    } catch (ex) { /* ignore */ }
  }

  function onResizeEnd() {
    isResizing = false
  }

  resizeHandle.addEventListener('mousedown', onResizeStart)
  resizeHandle.addEventListener('touchstart', onResizeStart, { passive: false })
  window.addEventListener('mousemove', onResizeMove)
  window.addEventListener('touchmove', onResizeMove, { passive: false })
  window.addEventListener('mouseup', onResizeEnd)
  window.addEventListener('touchend', onResizeEnd)

  container.appendChild(resizeHandle)

  // ============ Open / Close ============
  function openWindow() {
    if (isOpen) return
    isOpen = true
    btn.style.display = 'none'

    if (isMobile) {
      container.style.left = '0'
      container.style.top = '0'
      container.style.right = '0'
      container.style.bottom = '0'
      container.style.width = '100%'
      container.style.height = '100%'
      container.style.minWidth = '0'
      container.style.minHeight = '0'
      container.style.maxWidth = 'none'
      container.style.maxHeight = 'none'
      container.style.borderRadius = '0'
      resizeHandle.style.display = 'none'
      titleBar.style.cursor = 'default'
    } else {
      container.style.left = Math.max(0, (window.innerWidth - winW) / 2) + 'px'
      container.style.top = Math.max(0, (window.innerHeight - winH) / 2) + 'px'
      container.style.right = 'auto'
      container.style.bottom = 'auto'
    }

    container.style.display = 'flex'
  }

  function closeWindow() {
    if (!isOpen) return
    isOpen = false
    container.style.display = 'none'
    btn.style.display = 'flex'
  }

  // ============ Window resize handler ============
  var resizeTimer = null
  window.addEventListener('resize', function () {
    clearTimeout(resizeTimer)
    resizeTimer = setTimeout(function () {
      isMobile = window.innerWidth < 768
      if (isMobile && isOpen) {
        container.style.left = '0'
        container.style.top = '0'
        container.style.right = '0'
        container.style.bottom = '0'
        container.style.width = '100%'
        container.style.height = '100%'
        container.style.minWidth = '0'
        container.style.minHeight = '0'
        container.style.maxWidth = 'none'
        container.style.maxHeight = 'none'
        container.style.borderRadius = '0'
        resizeHandle.style.display = 'none'
        titleBar.style.cursor = 'default'
      } else if (!isMobile && isOpen) {
        resizeHandle.style.display = ''
      }
      // Keep button in bounds
      var bx = parseInt(btn.style.left, 10)
      var by = parseInt(btn.style.top, 10)
      if (bx > window.innerWidth - 52) btn.style.left = Math.max(0, window.innerWidth - 76) + 'px'
      if (by > window.innerHeight - 52) btn.style.top = Math.max(0, window.innerHeight - 76) + 'px'
    }, 200)
  })

})()
